export const categories = [
  {
    label: 'All',
    id: 'all'
  },
  {
    label: 'Hotel',
    id: 'hotel'
  },
  {
    label: 'Interior',
    id: 'interior'
  },
  {
    label: 'Portrait',
    id: 'portrait'
  },
  {
    label: 'Snap',
    id: 'snap'
  }
  /*
  {
    label: 'Others',
    id: 'others'
  }
  */
];

export const idToLabel = _id => {
  const category = categories.find(({ id }) => id === _id);
  return category.label;
};

export const labelToId = _label => {
  const category = categories.find(({ label }) => label === _label);
  return category.id;
};
